Condition.SQL:
DECLARE @CurrentLevel int
SELECT TOP 1 @CurrentLevel = [Level] FROM dbo.FolderTree WHERE ID = @ParentFolderTreeID
IF (@ParentFolderTreeID != @FolderTreeID) BEGIN SET @CurrentLevel = @CurrentLevel + 1;
/*DECLARE @Msg NVARCHAR(1000) = 'CurrentLevel: ' + CAST(@CurrentLevel AS VARCHAR(10)) ;THROW 50000, @Msg, 1;*/ END
SELECT IIF(@CurrentLevel = 2, 1, 0)

DataSource.SQL:
MERGE dbo.GroupFolderTree AS trg USING ( SELECT fotP.ID AS FolderTreeID ,gft.GroupID FROM usr.ITSMCategory AS itsCat INNER JOIN dbo.Folder AS fol ON fol.TableID = itsCat.ID AND fol.FormIdent = 'ITSMCategory' INNER JOIN dbo.FolderTree AS fot ON fot.FolderID = fol.ID INNER JOIN dbo.GroupFolderTree AS gft ON gft.FolderTreeID = fot.ID
INNER JOIN dbo.FolderTree AS fotP ON fot.Ident LIKE fotP.Ident + '%' AND fotP.ID != fot.ID
WHERE itsCat.ID = @ID ) AS src ON ( src.FolderTreeID = trg.FolderTreeID AND src.GroupID = trg.GroupID ) WHEN NOT MATCHED BY TARGET THEN INSERT (FolderTreeID, GroupID) VALUES (src.FolderTreeID, src.GroupID) ;
MERGE dbo.GroupFolderTreePermission AS trg USING ( SELECT gftPa.ID AS GroupFolderTreeID ,gftp.PermissionID FROM usr.ITSMCategory AS itsCat INNER JOIN dbo.Folder AS fol ON fol.TableID = itsCat.ID AND fol.FormIdent = 'ITSMCategory' INNER JOIN dbo.FolderTree AS fot ON fot.FolderID = fol.ID INNER JOIN dbo.GroupFolderTree AS gft ON gft.FolderTreeID = fot.ID INNER JOIN dbo.GroupFolderTreePermission AS gftp ON gftp.GroupFolderTreeID = gft.ID
INNER JOIN dbo.FolderTree AS fotP ON fot.Ident LIKE fotP.Ident + '%' AND fotP.ID != fot.ID INNER JOIN dbo.GroupFolderTree AS gftPa ON gftPa.FolderTreeID = fotP.ID AND gftPa.GroupID = gft.GroupID ) AS src ON ( src.GroupFolderTreeID = trg.GroupFolderTreeID AND src.PermissionID = trg.PermissionID ) WHEN NOT MATCHED BY TARGET THEN INSERT (GroupFolderTreeID, PermissionID) VALUES (src.GroupFolderTreeID, src.PermissionID) ;
