INNER JOIN dbo.FolderTree AS fotP ON fot.Ident LIKE fotP.Ident + '%' AND fotP.ID != fot.ID
WHERE itsCat.ID = @ID ) AS src ON ( src.FolderTreeID = trg.FolderTreeID AND src.AccountID = trg.AccountID ) WHEN NOT MATCHED BY TARGET THEN INSERT (FolderTreeID, AccountID) VALUES (src.FolderTreeID, src.AccountID) ;
